CREATE TABLE IF NOT EXISTS chunks (
  id      TEXT PRIMARY KEY,
  doc_id  TEXT,
  text    TEXT NOT NULL
);

// POST /ingest  { docId, text }
async function ingest(env, docId, fullText) {
  // 1) Split the document into small overlapping chunks
  const chunks = chunkText(fullText, 200, 40);

  // 2) Embed every chunk in one Workers AI call
  const { data } = await env.AI.run("@cf/baai/bge-base-en-v1.5", {
    text: chunks,
  });

  // 3) Save original text in D1, vectors in Vectorize
  const vectors = [];
  for (let i = 0; i < chunks.length; i++) {
    const id = docId + ":" + i;
    await env.DB.prepare(
      "INSERT OR REPLACE INTO chunks (id, doc_id, text) VALUES (?, ?, ?)"
    ).bind(id, docId, chunks[i]).run();
    vectors.push({ id, values: data[i], metadata: { docId } });
  }
  await env.VECTORIZE.upsert(vectors);
  return chunks.length;
}

// Split text into word chunks with a little overlap for context
function chunkText(text, size, overlap) {
  const words = text.split(/\s+/);
  const out = [];
  for (let i = 0; i < words.length; i += size - overlap) {
    out.push(words.slice(i, i + size).join(" "));
  }
  return out;
}

// POST /ask  { question }
async function ask(env, question) {
  // 1) Embed the question with the SAME model used at ingest
  const { data } = await env.AI.run("@cf/baai/bge-base-en-v1.5", {
    text: [question],
  });
  const queryVector = data[0];

  // 2) Retrieve the top-k most similar chunks from Vectorize
  const { matches } = await env.VECTORIZE.query(queryVector, {
    topK: 5,
    returnMetadata: true,
  });

  // 3) Load the original text of those chunks from D1
  const ids = matches.map((m) => m.id);
  const slots = ids.map(() => "?").join(", ");
  const { results } = await env.DB.prepare(
    "SELECT text FROM chunks WHERE id IN (" + slots + ")"
  ).bind(...ids).all();
  const context = results.map((r) => r.text).join("\n---\n");

  // 4) Generate an answer grounded ONLY in that context
  const out = await env.AI.run("@cf/meta/llama-3.1-8b-instruct", {
    messages: [
      {
        role: "system",
        content:
          "Answer using ONLY the context below. If it is not there, say you do not know.",
      },
      {
        role: "user",
        content: "Context:\n" + context + "\n\nQuestion: " + question,
      },
    ],
  });
  return out.response;
}

export default {
  async fetch(request, env) {
    const url = new URL(request.url);

    if (request.method === "POST" && url.pathname === "/ingest") {
      const { docId, text } = await request.json();
      const count = await ingest(env, docId, text);
      return Response.json({ ingested: count });
    }

    if (request.method === "POST" && url.pathname === "/ask") {
      const { question } = await request.json();
      const answer = await ask(env, question);
      return Response.json({ answer });
    }

    return new Response("POST JSON to /ingest or /ask", { status: 404 });
  },
};
